outputs.main.sas:
* Program: T1.1.sdtm_suppdm_gen.016.sas
* Purpose: Create SDTM SUPPDM (Supplemental DM) domain dataset
* Input: Raw supplemental DM data (suppdm_raw)
* Output: sdtm.suppdm (XPORT format)

* Setup;
libname raw "&_rawdata";
libname sdtm "&_sdtm";

* Read raw supplemental DM data;
data suppdm_raw;
  set raw.suppdm_raw;
run;

* Sort by USUBJID for sequential numbering;
proc sort data=suppdm_raw;
  by usubjid;
run;

* Derive SUPPDMSEQ and map variables;
data suppdm;
  length
    STUDYID $12
    RDOMAIN $2
    USUBJID $11
    IDVAR $8
    IDVARVAL $200
    QNAM $8
    QVAL $200
    QLABEL $40
    QORIG $1
    QEVAL $40
  ;

  retain STUDYID 'CDISCPILOT01'
         RDOMAIN 'DM'
  ;

  set suppdm_raw;
  by usubjid;

  * Derive sequential number per subject;
  if first.usubjid then seq = 0;
  seq + 1;
  SUPPDMSEQ = seq;

  * Map variables;
  USUBJID = usubjid;
  IDVAR = idvar;
  IDVARVAL = idvarval;
  QNAM = qnam;
  QVAL = qval;
  QLABEL = qlabel;
  QORIG = 'CRF';
  QEVAL = '';

  * Drop temporary variables;
  drop seq;
run;

* Sort by USUBJID and SUPPDMSEQ;
proc sort data=suppdm;
  by usubjid suppdmseq;
run;

* Apply variable attributes per SDTM specification;
data sdtm.suppdm (label='Supplemental Qualifiers for DM');
  attrib
    STUDYID   label='Study Identifier'                length=$12
    RDOMAIN   label='Related Domain Abbreviation'     length=$2
    USUBJID   label='Unique Subject Identifier'       length=$11
    IDVAR     label='Identifying Variable'            length=$8
    IDVARVAL  label='Identifying Variable Value'      length=$200
    QNAM      label='Qualifier Variable Name'         length=$8
    QVAL      label='Qualifier Variable Value'        length=$200
    QLABEL    label='Qualifier Variable Label'        length=$40
    QORIG     label='Qualifier Origin'                length=$1
    QEVAL     label='Evaluator'                       length=$40
  ;

  set suppdm;

  * Assign formats if needed;
  format _all_;
  informat _all_;
run;

* Create XPORT transport file;
proc copy in=sdtm out=work memtype=data;
  select suppdm;
run;

proc datasets lib=work nolist;
  modify suppdm;
    label STUDYID  = 'Study Identifier';
    label RDOMAIN  = 'Related Domain Abbreviation';
    label USUBJID  = 'Unique Subject Identifier';
    label IDVAR    = 'Identifying Variable';
    label IDVARVAL = 'Identifying Variable Value';
    label QNAM     = 'Qualifier Variable Name';
    label QVAL     = 'Qualifier Variable Value';
    label QLABEL   = 'Qualifier Variable Label';
    label QORIG    = 'Qualifier Origin';
    label QEVAL    = 'Evaluator';
  run;
quit;

* Export to XPORT format;
libname xport xport "&_sdtm/suppdm.xpt";

proc copy in=work out=xport memtype=data;
  select suppdm;
run;

libname xport clear;

* Verify record count;
proc sql;
  select count(*) as rec_count from sdtm.suppdm;
quit;
